# Find all people born in Germany with their birth years
PREFIX dbo: <http://dbpedia.org/ontology/>
PREFIX dbr: <http://dbpedia.org/resource/>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>

SELECT ?person ?name ?birthYear
WHERE {
  ?person a dbo:Person ;
          dbo:birthPlace ?place ;
          foaf:name ?name ;
          dbo:birthDate ?bd .
  ?place dbo:country dbr:Germany .
  BIND(YEAR(?bd) AS ?birthYear)
}
ORDER BY ?birthYear
LIMIT 10

# OWL 2 snippet in Turtle — defining a Person class with constraints
@prefix owl: <http://www.w3.org/2002/07/owl#> .
@prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .
@prefix xsd:  <http://www.w3.org/2001/XMLSchema#> .
@prefix ex:   <https://example.org/ontology#> .

ex:Person a owl:Class ;
    rdfs:label "Person"@en ;
    rdfs:comment "A human individual."@en .

ex:hasEmail a owl:DatatypeProperty ;
    rdfs:domain ex:Person ;
    rdfs:range  xsd:string ;
    a owl:FunctionalProperty .   # at most one email per person

ex:Employee rdfs:subClassOf ex:Person ;
    rdfs:subClassOf [
        a owl:Restriction ;
        owl:onProperty ex:hasEmail ;
        owl:minCardinality 1
    ] .  # every Employee must have an email

