# Full form — verbose but unambiguous
SELECT ?label WHERE {
  <https://www.wikidata.org/entity/Q64>
      <http://www.w3.org/2000/01/rdf-schema#label> ?label .
  FILTER(LANG(?label) = "en")
}

# Prefix form — identical semantics, readable
