# OWL 2 in Turtle — Mammal defined as a subclass of Animal
# with a transitive property and a defined class
@prefix owl:  <http://www.w3.org/2002/07/owl#> .
@prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .
@prefix ex:   <https://example.org/bio#> .

ex:Animal  a owl:Class .
ex:Mammal  a owl:Class ; rdfs:subClassOf ex:Animal .
ex:Dog     a owl:Class ; rdfs:subClassOf ex:Mammal .

# hasAncestor is transitive — if Dog subClassOf Mammal subClassOf Animal,
# a reasoner can infer Dog instances are also Animal instances
ex:hasAncestor a owl:TransitiveProperty .

# Defined class: Carnivore = Animal that eats only animals
ex:Carnivore a owl:Class ;
    owl:equivalentClass [
        a owl:Restriction ;
        owl:onProperty ex:eats ;
        owl:allValuesFrom ex:Animal
    ] .

# SHACL shape requiring every Person to have exactly one name
# and an email matching a regex pattern
@prefix sh:     <http://www.w3.org/ns/shacl#> .
@prefix ex:     <https://example.org/ontology#> .
@prefix xsd:    <http://www.w3.org/2001/XMLSchema#> .

ex:PersonShape
    a sh:NodeShape ;
    sh:targetClass ex:Person ;
    sh:property [
        sh:path  ex:name ;
        sh:minCount 1 ;
        sh:maxCount 1 ;
        sh:datatype xsd:string
    ] ;
    sh:property [
        sh:path    ex:email ;
        sh:minCount 1 ;
        sh:pattern "^[\\w.+-]+@[\\w-]+\\.[\\w.]+$"
    ] .

