# Wikidata SPARQL: Nobel Prize winners in Physics born after 1960
PREFIX wd:  <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>

SELECT ?person ?personLabel ?birthDate WHERE {
  ?person wdt:P166 wd:Q38104 ;   # award: Nobel Prize in Physics
          wdt:P569  ?birthDate . # date of birth
  FILTER(?birthDate > "1960-01-01"^^xsd:date)
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en" . }
}
ORDER BY ?birthDate

// Neo4j: create a product graph and run PageRank via GDS
// 1. Load graph into GDS in-memory catalog
CALL gds.graph.project(
  'productGraph',
  'Product',
  { SIMILAR_TO: { orientation: 'UNDIRECTED' } }
);

// 2. Run PageRank to find most influential products
CALL gds.pageRank.stream('productGraph', { maxIterations: 20, dampingFactor: 0.85 })
YIELD nodeId, score
RETURN gds.util.asNode(nodeId).name AS product, score
ORDER BY score DESC
LIMIT 10;

// 3. Drop the in-memory graph
CALL gds.graph.drop('productGraph');
